#!/usr/bin/perl
use strict;
use warnings;
use CAM::PDF;

# Function to extract specific information from a PDF
sub extract_pdf_info {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = CAM::PDF->new($pdf_file);

    # Extract metadata
    my $docinfo = $pdf->getDocumentInfo();
    my $date = $docinfo->{'/ModDate'};
    my $author = $docinfo->{'/Author'};

    # Extract table information (example: first table in the first page)
    my $pages = $pdf->getPageContent(1);
    if ($pages) {
        my $table_info = extract_tables($pages);
        return ($date, $author, $table_info);
    } else {
        return ($date, $author, 'No table found');
    }
}

# Function to extract tables from PDF content
sub extract_tables {
    my ($content) = @_;

    # This is a simple regex to identify tables. You may need to adjust it based on the structure of your PDF.
    my $table_pattern = qr/(\d+\s+\d+\s+\d+)/; # Example pattern to find table cells

    # Apply the regex to find table information
    if ($content =~ /$table_pattern/g) {
        my @matches = ($&);
        return join(", ", @matches);
    } else {
        return 'No table found';
    }
}

